export const processScenario = (scenario: Scenario) => {
  const results = [];

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const itemType = step.items[0].type;
      let premium = 0;

      // Base premiums
      if (itemType === "sword") {
        premium = 100;
      }

      // Initial assessment surcharge for first insurance
      if (scenario.customer.yearsWithMHPCO === 0) {
        premium = premium * 1.1;
      }

      // Processing fee
      premium += 5;

      // Round down in MHPCO's favor
      premium = Math.floor(premium);

      results.push({ premium });
    }
  }

  return { results };
};

