export interface Scenario {
  customer: {
    yearsWithMHPCO: number;
  };
  steps: Array<{
    op: "quote" | "claim";
    items?: Array<{
      type: string;
      material: string;
      enchantment: number;
      cursed: boolean;
    }>;
    policy?: number;
    incident?: {
      cause: string;
      damages: Array<{
        itemType: string;
        amount: number;
      }>;
    };
  }>;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  rune: 25,
};

const INITIAL_ASSESSMENT_SURCHARGE = 1.1; // 10% surcharge for first insurance
const PROCESSING_FEE = 5; // Fixed fee for all premiums

const calculateQuotePremium = (items: Array<any>, isFirstInsurance: boolean): number => {
  let premium = 0;

  // Check for 3 alike components
  if (items.length === 3 && items.every(item => item.type === items[0].type)) {
    premium = 60; // Special premium for 3 alike components
  } else {
    // Single item
    const itemType = items[0].type;
    premium = BASE_PREMIUMS[itemType] || 0;
  }

  // Initial assessment surcharge for first insurance
  if (isFirstInsurance) {
    premium = premium * INITIAL_ASSESSMENT_SURCHARGE;
  }

  // Processing fee
  premium += PROCESSING_FEE;

  // Round down in MHPCO's favor
  return Math.floor(premium);
};

export const processScenario = (scenario: Scenario) => {
  const results = [];

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const isFirstInsurance = scenario.customer.yearsWithMHPCO === 0;
      const premium = calculateQuotePremium(step.items, isFirstInsurance);
      results.push({ premium });
    }
  }

  return { results };
};

