  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const isFirstInsurance = scenario.customer.yearsWithMHPCO === 0;
      const premium = calculateQuotePremium(step.items, isFirstInsurance);
      results.push({ premium });
