const processClaim = (items: Array<any>, damages: Array<any>, insuranceSum: number): { payout: number; remainingCap: number } => {
  let totalDamage = 0;

  for (const damage of damages) {
    let payout = damage.amount;

    // Find the item for this damage
    const item = items.find(i => i.type === damage.itemType);

    // Damage to items with enchantment level >= 8 is reimbursed at 50%
    if (item && item.enchantment >= 8) {
      payout = payout * 0.5;
    }

    // Damage to items made of dragon material is fully reimbursed (no reduction)
    // Otherwise apply standard logic above

    totalDamage += payout;
  }

  // Apply deductible of 100 G per damage event
  let finalPayout = totalDamage - 100;
  if (finalPayout < 0) {
    finalPayout = 0;
  }

  // Cap at 2x insurance sum
  const cap = insuranceSum * 2;
  if (finalPayout > cap) {
    finalPayout = cap;
  }

  const remainingCap = cap - finalPayout;

  return { payout: Math.floor(finalPayout), remainingCap: Math.floor(remainingCap) };
};

export const processScenario = (scenario: Scenario) => {
  const results = [];
  const policies: Array<{ insuranceValue: number }> = [];

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      const premium = calculateQuotePremium(step.items, scenario.customer.yearsWithMHPCO);
      // Insurance value is based on the items (simplified for now)
      let insuranceValue = 0;
      if (step.items.length === 3) {
        insuranceValue = 60 * 2; // Assume components or special premium items
      } else {
        const itemType = step.items[0].type;
        const baseInsuranceMap: Record<string, number> = {
          sword: 1000,
          amulet: 600,
          staff: 800,
          potion: 400,
          rune: 250,
          moonstone: 250
        };
        insuranceValue = baseInsuranceMap[itemType] || 0;
      }
      policies.push({ insuranceValue });
      results.push({ premium });
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      const claimResult = processClaim(step.items || [], step.incident!.damages, policy.insuranceValue);
      results.push(claimResult);
    }
  }

  return { results };
};

